const FieldPosition = @import("field_position.zig").FieldPosition;

/// Stores the configuration information for a visual helper element for a form.
/// A sectional
/// element can be a header, a text block, or a divider. These elements are
/// static and not
/// associated with any data.
pub const SectionalElement = struct {
    /// Excludes a sectional element that was generated by default for a specified
    /// data
    /// model.
    excluded: ?bool,

    /// Specifies the size of the font for a `Heading` sectional element. Valid
    /// values
    /// are `1 | 2 | 3 | 4 | 5 | 6`.
    level: ?i32,

    /// Specifies the orientation for a `Divider` sectional element. Valid values
    /// are
    /// `horizontal` or `vertical`.
    orientation: ?[]const u8,

    /// Specifies the position of the text in a field for a `Text` sectional
    /// element.
    position: ?FieldPosition,

    /// The text for a `Text` sectional element.
    text: ?[]const u8,

    /// The type of sectional element. Valid values are `Heading`, `Text`,
    /// and `Divider`.
    @"type": []const u8,

    pub const json_field_names = .{
        .excluded = "excluded",
        .level = "level",
        .orientation = "orientation",
        .position = "position",
        .text = "text",
        .@"type" = "type",
    };
};
